  it.todo("should return empty grid when given empty grid");
  it.todo("should kill a single live cell with 0 neighbors");
  it.todo("should kill two adjacent live cells (each has only 1 neighbor)");
  it.todo("should preserve a 2x2 block (still life - each cell has 3 neighbors)");
  it.todo("should rotate a vertical blinker into a horizontal blinker");
